import numpy as np

class TrainingLogger:
    def __init__(self):
        self._history = {}

    def log(self, epoch: int, **metrics):
        for name, value in metrics.items():
            if name not in self._history:
                self._history[name] = []
            self._history[name].append((epoch, float(value)))

    def get_history(self, metric_name: str) -> list:
        if metric_name not in self._history:
            raise KeyError(f'Metric {metric_name!r} not found')
        return [v for _, v in self._history[metric_name]]

    def best(self, metric_name: str, mode: str = 'min') -> tuple:
        if metric_name not in self._history:
            raise KeyError(f'Metric {metric_name!r} not found')
        records = self._history[metric_name]
        if mode == 'min':
            epoch, value = min(records, key=lambda x: x[1])
        else:
            epoch, value = max(records, key=lambda x: x[1])
        return (value, epoch)

    def summary(self) -> dict:
        result = {}
        for name, records in self._history.items():
            vals = np.array([v for _, v in records])
            result[name] = {'mean': float(np.mean(vals)), 'min': float(np.min(vals)), 'max': float(np.max(vals))}
        return result
